INSERT INTO CASES (INDUSTRY, SCENARIO_TYPE, NAME, ATTRIBUTE_1, ATTRIBUTE_2, ATTRIBUTE_3, ATTRIBUTE_4, IS_FRAUD, EXPLANATION) VALUES ('Industrial', 'invoice', 'Uma Wong', 'received an invoice that matched the purchase order except for a freight surcharge and tax adjustment. The shipment had been expedited after a delay.', 'FREIGHT ADJUSTMENT', 'TAX CHANGE', 'PO MATCH', 'N', 'The invoice differences are explained by a shipping change.');
