INSERT INTO CASES (INDUSTRY, SCENARIO_TYPE, NAME, ATTRIBUTE_1, ATTRIBUTE_2, ATTRIBUTE_3, ATTRIBUTE_4, IS_FRAUD, EXPLANATION) VALUES ('Government', 'grant', 'Jade Tan', 'requested an advance grant disbursement for a time-sensitive project and the agency approved the exception in writing. The payment arrived before the milestone, but the process was followed.', 'ADVANCE DISBURSEMENT', 'WRITTEN APPROVAL', 'PRE-MILESTONE', 'N', 'The early payout was explicitly authorized.');
